import React, { useEffect, useState, useMemo } from "react";
import { supabase } from "../supabaseClient";
import { 
    Search, RefreshCcw, LogOut, MessageCircle, MapPin, 
    Clock, Calendar, CheckCircle, XCircle, Send, 
    Loader2, Car, Phone, ShieldCheck, Zap, User, ArrowRight, Smartphone
} from "lucide-react";
import "./Dashboard.css";

const Dashboard = ({ session }) => {
    const [rides, setRides] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [statusFilter, setStatusFilter] = useState("all");

    useEffect(() => {
        fetchRides();
        const channel = supabase.channel('realtime_rides')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides())
            .subscribe();
        return () => supabase.removeChannel(channel);
    }, []);

    const fetchRides = async () => {
        const { data } = await supabase.from("rides").select("*").order("created_at", { ascending: false });
        if (data) setRides(data);
        setLoading(false);
    };

    const handleStatus = async (id, newStatus) => {
        await supabase.from('rides').update({ status: newStatus }).eq('id', id);
        fetchRides();
    };

    const contactWA = (num, name, isAlt = false) => {
        const msg = isAlt ? `Emergency Backup for ${name}` : `Hi ${name}, PAHEL support here regarding your ride.`;
        window.open(`https://wa.me/91${num.replace(/\D/g, '')}?text=${encodeURIComponent(msg)}`, '_blank');
    };

    const filteredRides = useMemo(() => {
        return rides.filter(r => {
            const matchStatus = statusFilter === 'all' || r.status === statusFilter;
            const s = search.toLowerCase();
            const matchSearch = r.passenger_name?.toLowerCase().includes(s) || 
                               r.phone_number?.includes(s) || 
                               r.pickup_location?.toLowerCase().includes(s);
            return matchStatus && matchSearch;
        });
    }, [rides, search, statusFilter]);

    const stats = useMemo(() => ({
        total: rides.length,
        pending: rides.filter(x => x.status === 'pending').length,
        completed: rides.filter(x => x.status === 'completed').length
    }), [rides]);

    if (loading) return <div className="loader-container" style={{display:'flex',height:'100vh',justifyContent:'center',alignItems:'center'}}><Loader2 className="spinning" size={50} color="#2563eb" /></div>;

    return (
        <div className="app-container">
            <header className="dash-header">
                <div>
                    <h1>PAHEL Commander HQ</h1>
                    <p style={{color:'var(--text-muted)', fontWeight:500}}>Fleet Operation Center • Live</p>
                </div>
                <div style={{display:'flex', gap:'12px'}}>
                    <button className="op-btn" onClick={fetchRides}><RefreshCcw size={18}/> Refresh</button>
                    <button className="op-btn" style={{background:'var(--danger)', color:'#fff'}} onClick={() => supabase.auth.signOut()}><LogOut size={18}/> Logout</button>
                </div>
            </header>

            <div className="stats-container">
                <div className="glass-card">
                    <span className="stat-label">Total Rides</span>
                    <span className="stat-value">{stats.total}</span>
                    <Zap className="stat-icon" size={80} />
                </div>
                <div className="glass-card" style={{borderLeft:'6px solid var(--warning)'}}>
                    <span className="stat-label">Action Required</span>
                    <span className="stat-value" style={{color:'var(--warning)'}}>{stats.pending}</span>
                    <Clock className="stat-icon" size={80} />
                </div>
                <div className="glass-card" style={{borderLeft:'6px solid var(--success)'}}>
                    <span className="stat-label">Completed</span>
                    <span className="stat-value" style={{color:'var(--success)'}}>{stats.completed}</span>
                    <ShieldCheck className="stat-icon" size={80} />
                </div>
            </div>

            <div className="filter-engine">
                <div className="search-wrapper">
                    <Search size={20} style={{position:'absolute', left:'16px', top:'14px', color:'var(--text-muted)'}} />
                    <input placeholder="Search name, phone or location..." onChange={(e) => setSearch(e.target.value)} />
                </div>

                <div className="status-select-wrapper">
                    <select onChange={(e) => setStatusFilter(e.target.value)}>
                        <option value="all">All Status</option>
                        <option value="pending">Pending</option>
                        <option value="confirmed">Confirmed</option>
                        <option value="completed">Completed</option>
                        <option value="cancelled">Cancelled</option>
                    </select>
                </div>
            </div>

            <div className="table-wrapper">
                <table className="pahel-table">
                    <thead>
                        <tr>
                            <th>Passenger & Class</th>
                            <th>Contact Channels</th>
                            <th>Route Detail</th>
                            <th>Schedule Info</th>
                            <th>Status</th>
                            <th style={{textAlign:'right'}}>Operational Control</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredRides.map(r => (
                            <tr key={r.id}>
                                <td>
                                    <div style={{display:'flex', alignItems:'center', gap:'10px'}}>
                                        <div style={{width:35, height:35, borderRadius:'10px', background:'var(--primary-glow)', display:'flex', justifyContent:'center', alignItems:'center'}}>
                                            <User size={18} color="var(--primary)"/>
                                        </div>
                                        <div>
                                            <div style={{fontWeight:800}}>{r.passenger_name}</div>
                                            <div style={{fontSize:'12px', color:'var(--text-muted)', display:'flex', alignItems:'center', gap:'4px'}}><Car size={12}/> {r.vehicle_class}</div>
                                        </div>
                                    </div>
                                </td>
                                <td>
                                    <div style={{display:'flex', flexDirection:'column', gap:'6px'}}>
                                        <button onClick={() => contactWA(r.phone_number, r.passenger_name)} className="op-btn" style={{padding:'6px 10px', minWidth:'auto'}}><MessageCircle size={14} color="var(--success)"/> {r.phone_number}</button>
                                        {r.alt_phone && (
                                            <button onClick={() => contactWA(r.alt_phone, r.passenger_name, true)} className="op-btn" style={{padding:'6px 10px', minWidth:'auto', borderStyle:'dashed'}}><Smartphone size={14} color="var(--primary)"/> {r.alt_phone}</button>
                                        )}
                                    </div>
                                </td>
                                <td>
                                    <div className="route-box">
                                        <div style={{fontSize:'13px', fontWeight:700}}><span className="loc-dot" style={{background:'var(--success)', top:'5px'}}></span> {r.pickup_location}</div>
                                        <div style={{fontSize:'13px', fontWeight:700, marginTop:'8px'}}><span className="loc-dot" style={{background:'var(--danger)', bottom:'5px'}}></span> {r.drop_location}</div>
                                    </div>
                                </td>
                                <td>
                                    <div style={{fontWeight:700}}><Calendar size={14}/> {r.ride_date}</div>
                                    <div style={{fontSize:'12px', color:'var(--text-muted)'}}><Clock size={12}/> {r.ride_time}</div>
                                </td>
                                <td>
                                    <span style={{
                                        padding:'6px 12px', borderRadius:'10px', fontSize:'11px', fontWeight:800, textTransform:'uppercase',
                                        background: r.status === 'pending' ? '#fef3c7' : r.status === 'completed' ? '#dcfce7' : '#dbeafe',
                                        color: r.status === 'pending' ? '#92400e' : r.status === 'completed' ? '#166534' : '#1e40af'
                                    }}>{r.status}</span>
                                </td>
                                <td>
                                    <div className="action-btn-group">
                                        <button className="op-btn confirm" onClick={() => handleStatus(r.id, 'confirmed')}><Send size={14}/> Confirm Ride</button>
                                        <button className="op-btn complete" onClick={() => handleStatus(r.id, 'completed')}><CheckCircle size={14}/> Set Complete</button>
                                        <button className="op-btn cancel" onClick={() => handleStatus(r.id, 'cancelled')}><XCircle size={14}/> Cancel</button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            <style>{`.spinning { animation: spin 1s linear infinite; } @keyframes spin { 100% { transform: rotate(360deg); } }`}</style>
        </div>
    );
};

export default Dashboard;
